#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    int ch;
    while ((ch = getchar()) != '\n' && ch != EOF);
    for (int i = 0; i < T; ++i) {
        char buf[128];
        fgets(buf, sizeof(buf), stdin); // discard dummy line
        printf("CIVVIC\n");
    }
    return 0;
}

